
.contactum-toggle-switch {
  cursor: pointer;
  text-indent: -9999px;
  width: 25px;
  height: 15px;
  background: #ccc;
  display: block;
  border-radius: 100px;
  position: relative;
}
.contactum-toggle-switch:after {
  content: '';
  position: absolute;
  top: 2px;
  left: 2px;
  width: 12px;
  height: 12px;
  background: #fff;
  border-radius: 50%;
  transition: 0.3s;
}
.contactum-toggle-switch.checked {
  background: #0085ba;
}
.contactum-toggle-switch.checked:after {
  left: calc(90%);
  transform: translateX(-100%);
}
.contactum-toggle-switch.big {
  width: 35px;
  height: 20px;
}
.contactum-toggle-switch.big:after {
  top: 3px;
  left: 3px;
  width: 15px;
  height: 15px;
}
.contactum-toggle-switch.big.checked:after {
  left: calc(95%);
}
